import pytestimport pandas as pdimport numpy as npfrom Home_Work import AdvancedStudentAnalytics@pytest.fixturedef sample_df():    data = {        'name': ['Alice', 'Bob', 'Charlie', 'David', 'Eve'],        'group': ['A', 'A', 'B', 'B', 'C'],        'math': [90, 60, 90, 40, 90],        'physics': [90, 60, 90, 50, 90],        'cs': [90, 60, 90, 45, 90],        'attendance': [90, 55, 80, 55, 50],        'city': ['Moscow', 'Kazan', 'Moscow', 'Ufa', 'Kazan'],        'enrollment_year': [2021, 2021, 2022, 2022, 2023],        'scholarship': [True, False, False, False, True],        'project_score': [90, np.nan, 80, np.nan, 70]    }    return pd.DataFrame(data)@pytest.fixturedef analytics(sample_df):    return AdvancedStudentAnalytics(sample_df)def test_prepare_data_project_score(analytics):    assert analytics.df.loc[1, 'project_score'] == 60.0    assert analytics.df.loc[0, 'project_score'] == 90.0def test_prepare_data_average_grade(analytics):    assert analytics.df.loc[0, 'average_grade'] == 90.0def test_prepare_data_performance_level(analytics):    levels = analytics.df['performance_level'].tolist()    assert levels[0] == 'high'    assert levels[1] == 'low'def test_prepare_data_risk_level(analytics):    assert analytics.df.loc[1, 'risk_level'] == 'high risk'    assert analytics.df.loc[2, 'risk_level'] == 'low risk'def test_top_students(analytics):    top_2 = analytics.top_students(2)    assert len(top_2) == 2    assert top_2.iloc[0]['average_grade'] >= top_2.iloc[1]['average_grade']def test_group_stats(analytics):    stats = analytics.group_stats()    assert 'average_grade' in stats.columns    assert 'attendance' in stats.columns    assert 'name' in stats.columns    assert stats.loc['A', 'name'] == 2def test_at_risk_students(analytics):    risky = analytics.at_risk_students()    assert all(risky['risk_level'] == 'high risk')def test_hidden_top_students(analytics):    hidden = analytics.hidden_top_students()    assert len(hidden) == 1    assert hidden.iloc[0]['name'] == 'Charlie'def test_lazy_geniuses(analytics):    lazy = analytics.lazy_geniuses()    assert len(lazy) == 1    assert lazy.iloc[0]['name'] == 'Eve'def test_full_analysis_keys_and_types(analytics):    result = analytics.full_analysis()    assert isinstance(result, dict)    assert 'top_3' in result    assert isinstance(result.get('count_risk_students', result.get('at_risk_students')), int)    assert isinstance(result.get('hidden_top_students'), int)    assert isinstance(result.get('lazy_geniuses'), int)